import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.CMYkYJvz.js";const m=JSON.parse('{"title":"Matching Patterns","description":"Domain, path, wildcard, regex, and negated pattern behavior.","frontmatter":{"title":"Matching Patterns","description":"Domain, path, wildcard, regex, and negated pattern behavior.","editLink":false},"headers":[],"relativePath":"en/reference/patterns.md","filePath":"en/reference/patterns.md"}'),s={name:"en/reference/patterns.md"};function r(d,e,c,i,p,l){return a(),o("div",null,[...e[0]||(e[0]=[n(`<blockquote><p>This page is automatically synced from <code>docs-en/pattern.md</code>. Language: <strong>English</strong> | <a href="./../../reference/patterns">中文</a></p></blockquote><h1 id="matching-patterns" tabindex="-1">Matching Patterns <a class="header-anchor" href="#matching-patterns" aria-label="Permalink to &quot;Matching Patterns&quot;">​</a></h1><p>Patterns decide whether a rule applies to a request. Bifrost supports domain, IP, wildcard, regex, path, and negated patterns.</p><h2 id="common-forms" tabindex="-1">Common Forms <a class="header-anchor" href="#common-forms" aria-label="Permalink to &quot;Common Forms&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com</span></span>
<span class="line"><span>example.com/api</span></span>
<span class="line"><span>*.example.com</span></span>
<span class="line"><span>**.example.com</span></span>
<span class="line"><span>192.168.1.1</span></span>
<span class="line"><span>192.168.0.0/16</span></span>
<span class="line"><span>/pattern/i</span></span>
<span class="line"><span>!*.internal.example.com</span></span></code></pre></div><h2 id="guidance" tabindex="-1">Guidance <a class="header-anchor" href="#guidance" aria-label="Permalink to &quot;Guidance&quot;">​</a></h2><ul><li>Prefer precise domain and path patterns for debugging.</li><li>Use wildcard patterns for families of subdomains.</li><li>Use regex only when the simpler forms are not expressive enough.</li><li>HTTPS path matching usually requires TLS interception because CONNECT tunnels do not expose inner paths.</li></ul><blockquote><p>⚠️ <strong>Negated (<code>!</code>) patterns do not work at runtime (verified, 0.0.96).</strong> A <code>!X</code> pattern parses, but <code>matches_host()</code> always returns <code>false</code>, so a standalone <code>!</code>-prefixed pattern matches nothing — neither <code>X</code> nor non-<code>X</code> (verified: <code>!keep.test statusCode://249</code> returns no <code>249</code> for either <code>keep.test</code> or <code>other.test</code>, while the non-negated <code>pos.test statusCode://248</code> works). Don&#39;t use <code>!</code> as a router. To exclude a subset, use <code>excludeFilter://</code> instead (request-phase method/path/standard-header excludes work).</p></blockquote><h2 id="caveat-do-not-prefix-wildcard-patterns-with-a-scheme" tabindex="-1">Caveat: do not prefix wildcard patterns with a scheme <a class="header-anchor" href="#caveat-do-not-prefix-wildcard-patterns-with-a-scheme" aria-label="Permalink to &quot;Caveat: do not prefix wildcard patterns with a scheme&quot;">​</a></h2><p>Scheme prefixes (<code>http://</code>, <code>https://</code>, <code>http*://</code>, <code>ws*://</code>, <code>//</code>) are reliable only on Domain and PathWildcard (<code>^</code>) patterns. Combined with a wildcard host pattern they misbehave:</p><table tabindex="0"><thead><tr><th>Form</th><th>Actual behavior</th></tr></thead><tbody><tr><td><code>*.example.com</code> (bare, recommended)</td><td>Correctly matches one subdomain level (HTTP + HTTPS)</td></tr><tr><td><code>http://*.example.com</code> / <code>https://*.example.com</code></td><td>Matches, but the single <code>*</code> also spans <code>.</code>, behaving like <code>**</code></td></tr><tr><td><code>http*://*.example.com</code> / <code>ws*://*.example.com</code></td><td><strong>Never matches</strong> (silently)</td></tr><tr><td><code>//*.example.com</code></td><td><strong>Matches every host</strong> (over-broad — can hijack unrelated traffic)</td></tr></tbody></table><p>Write wildcard host patterns bare. To restrict by scheme, use a Domain pattern (e.g. <code>http*://api.example.com</code>) or a PathWildcard (e.g. <code>^http*://example.com/api/*</code>) instead. See <a href="./../../reference/patterns">中文 pattern.md</a> for the full table.</p>`,12)])])}const u=t(s,[["render",r]]);export{m as __pageData,u as default};
